            }

            Transform lodFolder = chunkPoolParent.Find(lod.ToString());

            if (lodFolder == null)
            {
                var folderObj = new GameObject(lod.ToString());
                folderObj.transform.SetParent(chunkPoolParent, false);
                lodFolder = folderObj.transform;
            }

            chunk.transform.SetParent(lodFolder, false);
            terrainJobSystemScript.GenerateChunk(position, lod, chunk.gameObject.GetComponent<Chunk>()); 
        }
    }

    public void DespawnChunk(Vector2Int position)
    {
        Debug.Log("Despawning chunk at " + position);
        if (!activeChunks.TryGetValue(position, out GameObject chunk))
        {
            Debug.LogWarning("No active chunk found at " + position + " to despawn.");
            return;
        }

        if (chunk != null)
        {
            chunk.SetActive(false);
            chunkPool.Add(chunk);
        }

        activeChunks.Remove(position);
    }
